    // views/ReportsView.tsx
    import React, { useState } from 'react';
    import { SaleRecord, Customer } from '../types';
    import { useTranslation } from 'react-i18next';

    interface ReportsViewProps {
      sales: SaleRecord[];
      customers: Customer[];
    }

    const SalesListReport: React.FC<{ sales: SaleRecord[]; customers: Customer[] }> = ({ sales, customers }) => {
      const [expandedSaleId, setExpandedSaleId] = useState<string | null>(null);
      const { t } = useTranslation();

      const getCustomerName = (customerId?: string) => {
        if (!customerId) return t('guest');
        const customer = customers.find(c => c.id === customerId);
        return customer ? customer.name : t('unknownCustomer');
      };

      return (
        <div className="bg-white rounded-xl shadow-md border overflow-hidden">
          <table className="w-full text-sm">
            <thead className="bg-slate-100 text-slate-600 uppercase">
              <tr>
                <th className="p-3 text-left">{t('date')}</th>
                <th className="p-3 text-left">{t('customer')}</th>
                <th className="p-3 text-left">{t('paymentMethod')}</th>
                <th className="p-3 text-right">{t('itemCount')}</th>
                <th className="p-3 text-right">{t('total')}</th>
                <th className="p-3"></th>
              </tr>
            </thead>
            <tbody>
              {sales.map(sale => (
                <React.Fragment key={sale.id}>
                  <tr className="border-b hover:bg-slate-50">
                    <td className="p-3">{new Date(sale.date).toLocaleString('tr-TR')}</td>
                    <td className="p-3">{getCustomerName(sale.customerId)}</td>
                    <td className="p-3">{sale.paymentMethod}</td>
                    <td className="p-3 text-right">{sale.items.reduce((s, i) => s + i.quantity, 0)}</td>
                    <td className="p-3 text-right font-bold text-cyan-700">{sale.total.toFixed(2)} ₺</td>
                    <td className="p-3">
                      <button onClick={() => setExpandedSaleId(p => p === sale.id ? null : sale.id)} className="text-cyan-600 hover:underline">
                        {t('detail')}
                      </button>
                    </td>
                  </tr>
                  {expandedSaleId === sale.id && (
                    <tr className="bg-cyan-50/50">
                      <td colSpan={6}>...</td>
                    </tr>
                  )}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
      );
    };

    const ReportsView: React.FC<ReportsViewProps> = (props) => {
      const { t } = useTranslation();
      return (
        <div className="p-4">
          <h2 className="text-2xl font-bold mb-4">{t('reports')}</h2>
          {/* ... other reports components ... */}
          <SalesListReport sales={props.sales} customers={props.customers} />
          {/* ... other reports components ... */}
        </div>
      );
    };

    export default ReportsView;
